refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
image = im2double(imresize(rgb2gray(image), [64 96]));
psf = imfspecial("gaussian", 9, 2);
blurred = imfilter(image, psf, "circular");
restored = imdeconvreg(blurred, psf, 0.01);
subplot(1, 3, 1);
imshow(image);
subplot(1, 3, 2);
imshow(blurred);
subplot(1, 3, 3);
imshow(immat2gray(restored));
